import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_BUTTON_GROUP } from '{{alias}}/core';
import {
  buttonGroupSeparatorVariants,
  type HbButtonGroupSeparatorOrientation,
} from './button-group.variants';

@Component({
  selector: 'hb-button-group-separator, [hb-button-group-separator]',
  template: ``,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    role: 'separator',
    '[attr.aria-orientation]': 'effectiveOrientation()',
    '[attr.data-slot]': "'button-group-separator'",
  },
  exportAs: 'hbButtonGroupSeparator',
})
export class HbButtonGroupSeparatorComponent {
  private readonly group = inject(HB_BUTTON_GROUP, { optional: true });

  readonly hbOrientation = input<HbButtonGroupSeparatorOrientation | undefined>(undefined);
  readonly class = input<ClassValue>('');

  protected readonly effectiveOrientation = computed<HbButtonGroupSeparatorOrientation>(() => {
    const own = this.hbOrientation();
    if (own) return own;
    const groupOrientation = this.group?.orientation() ?? 'horizontal';
    return groupOrientation === 'horizontal' ? 'vertical' : 'horizontal';
  });

  protected readonly classes = computed(() =>
    cn(buttonGroupSeparatorVariants({ orientation: this.effectiveOrientation() }), this.class()),
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { buttonGroupTextVariants } from './button-group.variants';

@Component({
  selector: 'hb-button-group-text, [hb-button-group-text]',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'button-group-text'",
  },
  exportAs: 'hbButtonGroupText',
})
export class HbButtonGroupTextComponent {
  readonly class = input<ClassValue>('');
  protected readonly classes = computed(() => cn(buttonGroupTextVariants(), this.class()));
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import {
  HB_BUTTON_GROUP,
  type HbButtonGroupContext,
  type HbButtonGroupOrientation,
  type HbButtonGroupSize,
} from '{{alias}}/core';
import { buttonGroupVariants } from './button-group.variants';

@Component({
  selector: 'hb-button-group, [hb-button-group]',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  providers: [{ provide: HB_BUTTON_GROUP, useExisting: HbButtonGroupComponent }],
  host: {
    '[class]': 'classes()',
    role: 'group',
    '[attr.data-slot]': "'button-group'",
    '[attr.data-orientation]': 'hbOrientation()',
  },
  exportAs: 'hbButtonGroup',
})
export class HbButtonGroupComponent implements HbButtonGroupContext {
  readonly hbOrientation = input<HbButtonGroupOrientation>('horizontal');
  readonly hbSize = input<HbButtonGroupSize | null>(null);
  readonly class = input<ClassValue>('');

  readonly size = this.hbSize;
  readonly orientation = this.hbOrientation;

  protected readonly classes = computed(() =>
    cn(buttonGroupVariants({ orientation: this.hbOrientation() }), this.class()),
  );
}

import { HbButtonGroupComponent } from './button-group.component';
import { HbButtonGroupSeparatorComponent } from './button-group-separator.component';
import { HbButtonGroupTextComponent } from './button-group-text.component';

export const HbButtonGroupImports = [
  HbButtonGroupComponent,
  HbButtonGroupSeparatorComponent,
  HbButtonGroupTextComponent,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const buttonGroupVariants = cva(
  cn(
    'flex w-fit items-stretch',
    '[&>*]:relative [&>*:focus-within]:z-10 [&>*:hover]:z-10',
    'has-[>[data-slot=button-group]]:gap-2',
  ),
  {
    variants: {
      orientation: {
        horizontal: cn(
          'flex-row',
          '[&>*:not([data-slot=button-group]):not(:first-child)]:-ml-px',
          '[&>*:not([data-slot=button-group]):not(:first-child)]:rounded-l-none',
          '[&>*:not([data-slot=button-group]):not(:last-child)]:rounded-r-none',
          '[&>hb-select:not(:first-child)>button]:rounded-l-none',
          '[&>hb-select:not(:last-child)>button]:rounded-r-none',
          '[&>hb-combobox:not(:first-child)>div]:rounded-l-none',
          '[&>hb-combobox:not(:last-child)>div]:rounded-r-none',
        ),
        vertical: cn(
          'flex-col',
          '[&>*:not([data-slot=button-group]):not(:first-child)]:-mt-px',
          '[&>*:not([data-slot=button-group]):not(:first-child)]:rounded-t-none',
          '[&>*:not([data-slot=button-group]):not(:last-child)]:rounded-b-none',
          '[&>hb-select:not(:first-child)>button]:rounded-t-none',
          '[&>hb-select:not(:last-child)>button]:rounded-b-none',
          '[&>hb-combobox:not(:first-child)>div]:rounded-t-none',
          '[&>hb-combobox:not(:last-child)>div]:rounded-b-none',
        ),
      },
    },
    defaultVariants: { orientation: 'horizontal' },
  },
);

export const buttonGroupSeparatorVariants = cva('shrink-0 self-stretch bg-border', {
  variants: {
    orientation: {
      vertical: 'w-px',
      horizontal: 'h-px w-full',
    },
  },
  defaultVariants: { orientation: 'vertical' },
});

export const buttonGroupTextVariants = cva(
  cn(
    'inline-flex items-center justify-center gap-1.5 whitespace-nowrap rounded-md border border-input',
    'bg-muted px-3 text-sm font-medium text-muted-foreground [&>ng-icon>svg]:size-4',
  ),
);

export type HbButtonGroupSeparatorOrientation = NonNullable<
  VariantProps<typeof buttonGroupSeparatorVariants>['orientation']
>;

export * from './button-group.component';
export * from './button-group-separator.component';
export * from './button-group-text.component';
export * from './button-group.variants';
export * from './button-group.imports';

